Boolean `@tracked` properties work exactly like string or number ones. Initialize to `false` or `true` explicitly — never leave it undefined when using it in `{{if}}` conditionals, even though `undefined` is falsy.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MatchScoreComponent extends Component {
  @tracked runs = 0;
  @tracked wickets = 0;
  @tracked overs = 0;
  @tracked isLive = true;
  @tracked currentBatsman = '';

  <template>
    <div class="flex gap-4">
      <span>{{this.runs}}/{{this.wickets}}</span>
      <span>{{this.overs}} ov</span>
      <span>{{this.currentBatsman}}</span>
    </div>
  </template>
