Assigning a completely new object literal to the `@tracked` property always triggers a re-render because the reference changes. This is the safest and most readable approach when all fields are being replaced, such as after loading fresh data from an API.

```gjs
import Component from '@glimmer/component';
import { TrackedArray } from 'tracked-built-ins';
import { action } from '@ember/object';

export default class BowlingFiguresComponent extends Component {
  bowlers = new TrackedArray(['Mustafizur', 'Taskin', 'Shoriful']);

  @action
  addBowler(name) {
    this.bowlers.push(name); // mutation is fine with TrackedArray
  }

  @action
  removeLast() {
    this.bowlers.pop();
  }

  <template>
