```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class OverCounterComponent extends Component {
  @tracked currentOver = 0;
  @tracked maxOvers = 20;

  @action
  nextOver() {
    if (this.currentOver < this.maxOvers) {
      this.currentOver = this.currentOver + 1;
    }
