import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class MultiPlayerSelectComponent extends Component {
  @tracked _selectedIds = new Set();

  get selectedIds() {
    return this._selectedIds;
  }

  isSelected(id) {
    return this._selectedIds.has(id);
  }

  get selectedCount() {
    return this._selectedIds.size;
  }

  @action
  togglePlayer(id) {
    const next = new Set(this._selectedIds);
    if (next.has(id)) {
      next.delete(id);
    } else {
      next.add(id);
    }
    this._selectedIds = next; // replace reference to trigger reactivity
  }

  @action
  clearAll() {
    this._selectedIds = new Set();
  }

  <template>
    <p>{{this.selectedCount}} selected</p>
    {{#each @players as |player|}}
      <label class="flex gap-2">
        <input
          type="checkbox"
          checked={{this.isSelected player.id}}
          {{on "change" (fn this.togglePlayer player.id)}}
        />
        {{player.name}}
      </label>
    {{/each}}
    <button {{on "click" this.clearAll}}>Clear All</button>
  </template>
}
