```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

const VALID_STATUSES = new Set(['idle', 'loading', 'success', 'error']);

export default class MatchFetcher extends Component {
  @tracked status = 'idle';
  @tracked matchData = null;

  @action
  setStatus(newStatus) {
    if (!VALID_STATUSES.has(newStatus)) {
      console.warn(`Invalid status: ${newStatus}`);
      return;
    }
    this.status = newStatus;
  }

  @action
  async loadMatch() {
    this.setStatus('loading');
    try {
      const res = await fetch(`/api/matches/${this.args.matchId}`);
      this.matchData = await res.json();
      this.setStatus('success');
    } catch {
      this.setStatus('error');
    }
  }

  <template>
    <button type="button" {{on "click" this.loadMatch}} class="px-4 py-2 bg-green-700 text-white rounded">
      Load Match
    </button>
    <p class="mt-2 text-sm">Status: {{this.status}}</p>
  </template>
}
```
A `setStatus` helper action centralizes status transitions. Using a `Set` for validation prevents typos from entering the tracked property. This pattern is especially useful in async `@action` methods where status changes at multiple points.

