    { id: 1, name: 'Tamim Iqbal' },
    { id: 2, name: 'Liton Das' },
    { id: 3, name: 'Shakib Al Hasan' },
    { id: 4, name: 'Mushfiqur Rahim' },
  ];

  @action
  swapPositions(indexA, indexB) {
    const updated = [...this.lineup];
    [updated[indexA], updated[indexB]] = [updated[indexB], updated[indexA]];
    this.lineup = updated;
  }

  <template>
    <ol class="space-y-1">
      {{#each this.lineup as |player i|}}
        <li class="flex items-center gap-2">
          <span class="font-bold text-green-700">{{add i 1}}.</span>
          {{player.name}}
          {{#if (gt i 0)}}
            <button type="button" {{on "click" (fn this.swapPositions i (sub i 1))}} class="text-xs text-gray-400">
              ↑
            </button>
          {{/if}}
        </li>
      {{/each}}
    </ol>
  </template>
}
