```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class CountdownTimer extends Component {
  @tracked elapsedSeconds = 0;
  @tracked isRunning = false;
  #intervalId = null;

  get formattedTime() {
    const m = Math.floor(this.elapsedSeconds / 60).toString().padStart(2, '0');
    const s = (this.elapsedSeconds % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  }

  @action
  startTimer() {
    if (this.isRunning) return;
    this.isRunning = true;
    this.#intervalId = setInterval(() => {
      this.elapsedSeconds += 1;
    }, 1000);
  }

  @action
  stopTimer() {
    clearInterval(this.#intervalId);
    this.#intervalId = null;
    this.isRunning = false;
  }

  willDestroy() {
    super.willDestroy();
    this.stopTimer();
  }

  <template>
    <p class="font-mono text-3xl">{{this.formattedTime}}</p>
    <div class="flex gap-2 mt-2">
      <button type="button" {{on "click" this.startTimer}} disabled={{this.isRunning}} class="px-3 py-1 bg-green-700 text-white rounded disabled:opacity-40">Start</button>
      <button type="button" {{on "click" this.stopTimer}} disabled={{not this.isRunning}} class="px-3 py-1 bg-red-600 text-white rounded disabled:opacity-40">Stop</button>
    </div>
  </template>
}
```
The interval id is stored in a private class field `#intervalId` — a plain non-tracked property — because it's implementation detail, not UI state. `willDestroy` clears the interval to prevent memory leaks and errors on destroyed component instances.

