```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class AsyncAction extends Component {
  @tracked matchData = null;
  @tracked isLoading = false;
  @tracked error = null;

  // @action works correctly on async methods
  // 'this' is bound, and tracked updates inside the async body work
  @action
  async loadMatch() {
    this.isLoading = true;   // Triggers re-render 1
    this.error = null;
    try {
      const res = await fetch(`/api/matches/${this.args.matchId}`);
      this.matchData = await res.json(); // Triggers re-render 2 (after await)
    } catch (err) {
      this.error = err.message;           // Triggers re-render 2 on error path
    } finally {
      this.isLoading = false;             // Triggers re-render 3
    }
  }

  <template>
    <button type="button" {{on "click" this.loadMatch}}>Load</button>
    {{#if this.isLoading}}<p>Loading...</p>{{/if}}
    {{#if this.matchData}}<p>{{this.matchData.title}}</p>{{/if}}
    {{#if this.error}}<p class="text-red-500">{{this.error}}</p>{{/if}}
  </template>
}
```
`@action` on an async function is valid — it still fixes `this` binding correctly. The function returns a Promise, but the `{{on}}` helper discards the return value so unhandled rejection must be managed inside the action (with try/catch). Each tracked assignment after an `await` point schedules its own re-render, so the UI updates progressively as the async operation proceeds.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class MemoizationDemo extends Component {
  @tracked runs = 50;
  @tracked wickets = 3;
  @tracked unrelatedFlag = false;

  computeCallCount = 0;

  get strikeRate() {
    this.computeCallCount++;
    console.log(`strikeRate computed: call #${this.computeCallCount}`);
