```
Glimmer components are designed around unidirectional data flow: data down via args, actions up via callbacks. Calling an `@action` from outside the component creates hidden coupling between components, makes the data flow implicit and hard to trace, and can cause state updates to occur without the parent's knowledge. It also violates the assumption that `@tracked` state is local to the component. Instead, use `@args` callback functions to allow parents to coordinate state changes through the standard data-down, actions-up pattern.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class OptimisticLike extends Component {
  @tracked isLiked = this.args.initiallyLiked ?? false;
  @tracked likeCount = this.args.initialCount ?? 0;
  @tracked isSaving = false;

  @action
  async toggleLike() {
    // 1. Update UI IMMEDIATELY (optimistic)
    this.isLiked = !this.isLiked;
    this.likeCount += this.isLiked ? 1 : -1;
    this.isSaving = true;
    try {
      await fetch(`/api/matches/${this.args.matchId}/like`, {
        method: this.isLiked ? 'POST' : 'DELETE',
      });
    } catch {
      // 2. Revert on failure
      this.isLiked = !this.isLiked;
      this.likeCount += this.isLiked ? 1 : -1;
    } finally {
      this.isSaving = false;
    }
  }

  <template>
    <button type="button" {{on "click" this.toggleLike}} disabled={{this.isSaving}}
      class="flex items-center gap-1 {{if this.isLiked 'text-red-500' 'text-gray-400'}}">
      ♥ {{this.likeCount}}
    </button>
  </template>
}
```
`@tracked` makes optimistic updates natural: mutate local state immediately for instant visual feedback, then fire the async request. If the request fails, simply revert the tracked values. Because tracked updates are synchronous and render asynchronously, the optimistic change appears in the UI before the network round-trip completes.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';

export default class BooleanVsString extends Component {
  // ✅ Use BOOLEAN for simple two-state UI toggles
  @tracked isMenuOpen = false;
  @tracked isExpanded = false;
  @tracked isDarkMode = false;

  // ✅ Use STRING ENUM for multi-state async operations
  @tracked fetchStatus = 'idle'; // 'idle' | 'loading' | 'success' | 'error'

  // ❌ SMELL: using string where boolean is clearer
  // @tracked menuState = 'closed'; // 'open' | 'closed'
  // Requires eq helper in template: {{if (eq this.menuState 'open') ...}}
  // vs boolean: {{if this.isMenuOpen ...}}

  <template>
    {{#if this.isMenuOpen}}
      <nav>Menu content</nav>
    {{/if}}
    {{if (eq this.fetchStatus 'loading') 'Loading...' 'Ready'}}
  </template>
