Because services are singletons, both components hold a reference to the *same* service instance. Both templates read the same `@tracked score` property, registering the same revision tag as a dependency. When `score` changes (e.g., via a WebSocket update), that single tag is bumped once, and Glimmer marks *all* consumers of that tag as dirty — both components, regardless of where they are in the component tree. They both re-render in the next microtask.

```gjs
import Component from '@glimmer/component';
import { tracked } from '@glimmer/tracking';
import { action } from '@ember/object';

export default class DeepNested extends Component {
  @tracked team = {
    name: 'Bangladesh',
    captain: { name: 'Shakib', age: 36 },
    score: { runs: 0, wickets: 0 },
  };

  @action
  addRun() {
    // ❌ WRONG: nested mutation — tracked setter never called
    // this.team.score.runs += 1;

    // ✅ CORRECT: replace ALL objects in the chain
    this.team = {
      ...this.team,
      score: { ...this.team.score, runs: this.team.score.runs + 1 },
    };
  }

  <template>
    <p>{{this.team.name}}: {{this.team.score.runs}}/{{this.team.score.wickets}}</p>
