  // @tracked strikeRate = 150.0;
  // @tracked isGoodBatsman = true;
  // These can go out of sync with runs/balls

  // ✅ CORRECT: derive from minimal tracked state
  get strikeRate() {
    return balls > 0 ? ((this.runs / this.balls) * 100).toFixed(1) : '0.0';
